const env = typeof $env !== 'undefined' ? $env : {};
const supabaseUrl = (env.SUPABASE_URL || process.env.SUPABASE_URL || '').replace(/\/$/, '');
const serviceRoleKey = env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_SERVICE_ROLE_KEY || '';

if (!supabaseUrl || !serviceRoleKey) {
  throw new Error('Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY in n8n environment.');
}

const restHeaders = {
  apikey: serviceRoleKey,
  Authorization: `Bearer ${serviceRoleKey}`,
  'Content-Type': 'application/json',
};

async function httpRequest(options) {
  return this.helpers.httpRequest({ json: true, ...options });
}

async function supabaseGet(path) {
  return httpRequest.call(this, { method: 'GET', url: `${supabaseUrl}/rest/v1/${path}`, headers: restHeaders });
}

async function supabasePost(path, body) {
  return httpRequest.call(this, {
    method: 'POST',
    url: `${supabaseUrl}/rest/v1/${path}`,
    headers: { ...restHeaders, Prefer: 'return=representation' },
    body,
  });
}

function enc(value) {
  return encodeURIComponent(String(value));
}

function utcDate(date = new Date()) {
  return date.toISOString().slice(0, 10);
}

function timeToMinutes(value) {
  const [hours = '0', minutes = '0'] = String(value || '00:00').split(':');
  return Number(hours) * 60 + Number(minutes);
}

function compactIds(rows, key = 'id', max = 20) {
  return (rows || []).map((row) => row[key]).filter(Boolean).slice(0, max);
}

const now = new Date();
const today = utcDate(now);
const sevenDaysAgoIso = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString();
const tomorrowIso = new Date(now.getTime() + 24 * 60 * 60 * 1000).toISOString();
const currentMinutes = now.getUTCHours() * 60 + now.getUTCMinutes();
const currentDow = now.getUTCDay();
const runStartedAt = now.toISOString();

const coaches = (await supabaseGet('coach_profiles?select=id,user_id,status&user_id=not.is.null&limit=1000')).filter((coach) => coach.user_id);
const schedules = await supabaseGet('check_in_schedules?select=id,coach_id,client_id,frequency,check_in_days,check_in_time&enabled=eq.true&limit=1000');
const recentResponses = await supabaseGet(`check_in_responses?select=id,coach_id,client_id,response_date,mood,energy,sleep_quality,responded_at&responded_at=gte.${enc(sevenDaysAgoIso)}&limit=2000`);
const upcomingBookings = await supabaseGet(`bookings?select=id,coach_id,client_id,scheduled_at,status&status=eq.confirmed&scheduled_at=gte.${enc(now.toISOString())}&scheduled_at=lte.${enc(tomorrowIso)}&limit=2000`);
const activePacks = await supabaseGet('purchased_packs?select=id,coach_id,client_id,status&status=eq.active&limit=2000');
const coachBookings = await supabaseGet('bookings?select=id,coach_id,client_id,status,scheduled_at&limit=3000');
const clientHealthToday = await supabaseGet(`bi_client_health_daily?select=user_id,metric_date,days_since_last_completed_workout,days_since_last_completed_booking,completed_workout_days_last_7d,nutrition_log_days_last_7d&metric_date=eq.${today}&limit=3000`);

const results = [];
const stats = {
  run_started_at: runStartedAt,
  digest_date: today,
  coaches_found: coaches.length,
  created_count: 0,
  skipped_no_signal_count: 0,
  skipped_existing_digest_count: 0,
  error_count: 0,
};

function scheduleIsDue(schedule) {
  const days = Array.isArray(schedule.check_in_days) ? schedule.check_in_days.map(Number) : [];
  const dayMatches = schedule.frequency === 'daily' || days.includes(currentDow);
  return dayMatches && currentMinutes >= timeToMinutes(schedule.check_in_time);
}

function lowWellness(response) {
  return Number(response.mood) <= 2 || Number(response.energy) <= 2 || Number(response.sleep_quality) <= 2;
}

function isInactive(health) {
  const workoutDays = Number(health.completed_workout_days_last_7d || 0);
  const nutritionDays = Number(health.nutrition_log_days_last_7d || 0);
  const daysSinceWorkout = health.days_since_last_completed_workout == null ? 999 : Number(health.days_since_last_completed_workout);
  const daysSinceBooking = health.days_since_last_completed_booking == null ? 999 : Number(health.days_since_last_completed_booking);
  return workoutDays === 0 && nutritionDays === 0 && daysSinceWorkout >= 7 && daysSinceBooking >= 7;
}

for (const coach of coaches) {
  try {
    const coachSchedules = (schedules || []).filter((schedule) => schedule.coach_id === coach.id && scheduleIsDue(schedule));
    const missedCheckIns = [];
    for (const schedule of coachSchedules) {
      const hasResponse = (recentResponses || []).some((response) => response.coach_id === coach.id && response.client_id === schedule.client_id && response.response_date === today);
      if (!hasResponse) missedCheckIns.push(schedule);
    }

    const lowWellnessResponses = (recentResponses || []).filter((response) => response.coach_id === coach.id && lowWellness(response));
    const upcoming = (upcomingBookings || []).filter((booking) => booking.coach_id === coach.id);
    const activeClientIds = new Set([
      ...(activePacks || []).filter((pack) => pack.coach_id === coach.id).map((pack) => pack.client_id),
      ...(coachBookings || []).filter((booking) => booking.coach_id === coach.id).map((booking) => booking.client_id),
    ].filter(Boolean));
    const inactiveClients = (clientHealthToday || []).filter((health) => activeClientIds.has(health.user_id) && isInactive(health));

    const signalCount = missedCheckIns.length + lowWellnessResponses.length + upcoming.length + inactiveClients.length;
    if (signalCount === 0) {
      stats.skipped_no_signal_count += 1;
      results.push({ coach_id: coach.id, coach_user_id: coach.user_id, status: 'skipped_no_signal' });
      continue;
    }

    const existing = await supabaseGet(`notifications?select=id&user_id=eq.${coach.user_id}&data->>kind=eq.coach_daily_digest&data->>digest_date=eq.${today}&limit=1`);
    if (existing[0]?.id) {
      stats.skipped_existing_digest_count += 1;
      results.push({ coach_id: coach.id, coach_user_id: coach.user_id, status: 'skipped_existing_digest', notification_id: existing[0].id });
      continue;
    }

    const body = `${missedCheckIns.length} missed check-ins, ${lowWellnessResponses.length} low wellness signals, ${upcoming.length} upcoming sessions, ${inactiveClients.length} inactive clients.`;
    const inserted = await supabasePost('notifications', {
      user_id: coach.user_id,
      type: 'booking_reminder',
      title: 'Daily client digest',
      body,
      data: {
        kind: 'coach_daily_digest',
        digest_date: today,
        coach_id: coach.id,
        missed_check_in_count: missedCheckIns.length,
        low_wellness_count: lowWellnessResponses.length,
        upcoming_booking_count: upcoming.length,
        inactive_client_count: inactiveClients.length,
        missed_check_in_schedule_ids: compactIds(missedCheckIns),
        low_wellness_response_ids: compactIds(lowWellnessResponses),
        upcoming_booking_ids: compactIds(upcoming),
        inactive_client_ids: compactIds(inactiveClients, 'user_id'),
        generated_at: new Date().toISOString(),
      },
    });

    const notification = inserted[0];
    if (!notification?.id) throw new Error('Supabase did not return inserted notification id.');
    stats.created_count += 1;
    results.push({ coach_id: coach.id, coach_user_id: coach.user_id, status: 'created', notification_id: notification.id, signal_count: signalCount });
  } catch (error) {
    stats.error_count += 1;
    results.push({ coach_id: coach.id, coach_user_id: coach.user_id, status: 'error', error: error instanceof Error ? error.message : String(error) });
  }
}

return [
  { json: { type: 'summary', status: stats.error_count > 0 ? 'completed_with_errors' : 'completed', finished_at: new Date().toISOString(), ...stats } },
  ...results.map((result) => ({ json: { type: 'coach_result', ...result } })),
];
